import express from 'express';

const app = express();

app.post('/send', express.json(), async (req, res) => {
  const { data } = req.body;
  // In a real app, use a shared state layer like Redis 7.2
  // For demo, we just echo back
  res.json({ echo: data });
});

app.listen(3000);
```

